import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder rawBuilder = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            rawBuilder.append(line).append("\n");
        }
        String rawInput = rawBuilder.toString().trim();
        // Convert escaped "\n" sequences to actual newlines
        rawInput = rawInput.replace("\\n", "\n");
        String[] parts = rawInput.split("\n");
        int idx = 0;
        int T = Integer.parseInt(parts[idx++].trim());
        StringBuilder output = new StringBuilder();
        for (int tc = 0; tc < T; tc++) {
            if (idx >= parts.length) break; // safety
            String s = parts[idx++];
            if (idx >= parts.length) break;
            String t = parts[idx++];
            int n = s.length();
            int m = t.length();
            int[][] dp = new int[n + 1][m + 1];
            for (int i = 1; i <= n; i++) {
                char si = s.charAt(i - 1);
                for (int j = 1; j <= m; j++) {
                    if (si == t.charAt(j - 1)) {
                        dp[i][j] = dp[i - 1][j - 1] + 1;
                    } else {
                        dp[i][j] = Math.max(dp[i - 1][j], dp[i][j - 1]);
                    }
                }
            }
            output.append(dp[n][m]).append('\n');
        }
        System.out.print(output.toString());
    }
}

